// Clean text function to remove extra whitespace and blank lines
function cleanText(text) {
  return (text || '').replace(/\n{2,}/g, '\n').replace(/[ \t]+\n/g, '\n').replace(/\n[ \t]+/g, '\n').trim();
}

// Function to check if text contains Cyrillic characters
function hasCyrillic(text) {
  return /[а-яА-ЯіІїЇєЄґҐ]/.test(text);
}

// Function to check if all options are in the same language
function validateOptionsLanguage(options) {
  if (!options || options.length !== 4) return false;

  const firstOptionHasCyrillic = hasCyrillic(options[0]);

  // Check if all options match the language of the first option
  return options.every(option => hasCyrillic(option) === firstOptionHasCyrillic);
}

// Парсимо Quiz JSON від AI
