  }

  const messageText = $json.text || '';
  const messageHash = messageText.split('').reduce((hash, char) => {
    return ((hash << 5) - hash) + char.charCodeAt(0);
  }, 0).toString();

  const lastHash = staticData.lastSentMessageHash['-1002680027938'];

  if (lastHash === messageHash) {
    throw new Error('Duplicate message detected - skipping send');
  }

  staticData.lastSentMessageHash['-1002680027938'] = messageHash;

  return messageText;
}}

