const messageText = message.text || '';

// Check if this is a reply to Tuesday Challenge post
const replyToMessageId = message.reply_to_message?.message_id;
if (!replyToMessageId) {
  return [{ json: { stored: false, reason: 'Not a reply to challenge post' } }];
}

// Find the active Tuesday challenge
const activeChallenge = staticData.tuesdayChallenges[staticData.tuesdayChallenges.length - 1];
if (!activeChallenge) {
  return [{ json: { stored: false, reason: 'No active challenge found' } }];
}

// Parse submission (expecting format: "English sentence — Ukrainian translation")
const parts = messageText.split('—').map(s => s.trim());
const sentenceEn = parts[0] || messageText;
const sentenceUa = parts[1] || '';

// Create submission object
const submission = {
  user_id: userId,
  username: username,
  sentence_en: sentenceEn,
  sentence_ua: sentenceUa,
  submitted_at: new Date().toISOString(),
  message_id: message.message_id
};

// Add submission to active challenge
if (!activeChallenge.submissions) {
  activeChallenge.submissions = [];
}
activeChallenge.submissions.push(submission);

// Award +10 points for participation
if (!staticData.userPoints) {
  staticData.userPoints = {};
}
if (!staticData.userPoints[userId]) {
  staticData.userPoints[userId] = {
    user_id: userId,
    username: username,
    points: 0,
    last_updated: new Date().toISOString()
  };
}
staticData.userPoints[userId].points += 10;
staticData.userPoints[userId].last_updated = new Date().toISOString();

return [{ json: {
  stored: true,
  user_id: userId,
  username: username,
  sentence_en: sentenceEn,
  sentence_ua: sentenceUa,
  challenge_word: activeChallenge.word,
  total_submissions: activeChallenge.submissions.length,
