}}];

const content = $('✍️ Форматування посту').item.json.text || '';
const wordMatch = content.match(/🔤\s*СЛОВО ДНЯ\s*\n([A-Z]+)/i) || content.match(/\b([A-Z]{3,})\b/);
const word = wordMatch ? wordMatch[1] : 'Hello';
return [{ json: { word: word, original_content: content } }];

// Check for duplicate messages to prevent sending the same content twice
const staticData = $getWorkflowStaticData('global');

// Initialize sentMessages array if it doesn't exist
if (!staticData.sentMessages) {
  staticData.sentMessages = [];
}

const input = $input.first();
const messageText = input.json.text || '';

// Calculate simple hash from first 100 characters
const textToHash = messageText.substring(0, 100);
const hash = textToHash.split('').reduce((hash, char) => {
  return ((hash << 5) - hash) + char.charCodeAt(0);
}, 0).toString();

// Check if hash exists in sentMessages array
if (staticData.sentMessages.includes(hash)) {
  // Duplicate detected - return empty array to stop flow
  return [];
}

// Unique message - add hash to array and continue
staticData.sentMessages.push(hash);

// Keep only last 100 hashes to prevent memory issues
if (staticData.sentMessages.length > 100) {
  staticData.sentMessages = staticData.sentMessages.slice(-100);
}

// Return input data to continue flow
return [{ json: input.json }];

const currentData = $input.first().json;

const existingUserData = {};

return [
  {
        json: {
                ...existingUserData,
                ...currentData,
        }
  }
  ];

// Get last 3 words from Google Sheets Used Words
const usedWords = $('💾 Static Data - Get Used Words').all();
const last3Words = usedWords.slice(-3);

// Extract word data
