  word: item.json.word || 'UNKNOWN',
  translation: item.json.translation || 'переклад',
  content_type: item.json.content_type || 'word'
}));

// Generate 3 test questions with 4 options each (all same language)
const questions = words.map((wordData, index) => {
  const correctAnswer = wordData.translation;

  // Generate 3 wrong options in the same language (Ukrainian)
  const wrongOptions = [
    'красивий',
    'складний',
    'важливий',
    'швидкий',
    'цікавий',
    'корисний'
  ].filter(opt => opt !== correctAnswer).slice(0, 3);

  // Shuffle options
  const allOptions = [correctAnswer, ...wrongOptions].sort(() => Math.random() - 0.5);
  const correctIndex = allOptions.indexOf(correctAnswer);

  return {
    word: wordData.word,
    question: `Що означає ${wordData.word}?`,
    options: allOptions,
    correct_index: correctIndex
  };
});

// Format test text
const wordsLearned = words.map(w => w.word).join(', ');
const testText = `🧪 <b>ТЕСТ ДНЯ</b>\n\nВчора вивчили: <b>${wordsLearned}</b>\n━━━━━━━━━━━━━━━━━\n\nПитання 1/3: ${questions[0].question}\n\n❤️❤️❤️\n\n━━━━━━━━━━━━━━━━━\n\nA) ${questions[0].options[0]}\nB) ${questions[0].options[1]}\nC) ${questions[0].options[2]}\nD) ${questions[0].options[3]}`;

return [{ json: {
  test_text: testText,
  questions: questions,
  words_tested: words.map(w => w.word)
}}];

const staticData = $getWorkflowStaticData('global');
if (!staticData.users) staticData.users = {};

const userId = $('📩 Telegram — всі повідомлення').item.json.message?.from?.id;
if (!userId) return [];

const user = staticData.users[userId] || {
  user_id: userId,
  username: $('📩 Telegram — всі повідомлення').item.json.message?.from?.username || '',
  xp: 0,
  streak: 0,
