  league: 'Bronze',
  level: 'A1',
  last_active: '',
  words_learned: 0,
  correct_answers: 0,
  wrong_answers: 0
};

return [{ json: user }];

const staticData = $getWorkflowStaticData('global');
if (!staticData.users) staticData.users = {};

const input = $input.first().json;
const userId = input.user_id;

if (!userId) return [];

staticData.users[userId] = {
